package DecisionMakingStatement;

public class Switch_Statement {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int num = 3;
		
		switch(num) {
		case 0:
			System.out.println("number is 0: coforge");
			break;
			
		case 1:
			System.out.println("number is 1: ramesh");
			break;
			
		case 2:
			System.out.println("number is 2: jitra");
			break;
			
		case 3:
			System.out.println("number is 3: rajjj");
			break;
			
		default:
			System.out.println(num);
		
		}

	}

}
